import{_ as e,o as a,c as o,a2 as r}from"./chunks/framework.BZO4qERu.js";const u=JSON.parse('{"title":"智能路由","description":"自动选择最优模型","frontmatter":{"title":"智能路由","description":"自动选择最优模型"},"headers":[],"relativePath":"zh/guide/smart-routing.md","filePath":"zh/guide/smart-routing.md"}'),d={name:"zh/guide/smart-routing.md"};function n(s,t,i,l,c,h){return a(),o("div",null,[...t[0]||(t[0]=[r(`<h1 id="智能路由" tabindex="-1">智能路由 <a class="header-anchor" href="#智能路由" aria-label="Permalink to &quot;智能路由&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>智能路由功能根据请求复杂度自动选择最优模型。设置 <code>model: &quot;auto&quot;</code>，WebRouter 自动决策。</p><h2 id="工作原理" tabindex="-1">工作原理 <a class="header-anchor" href="#工作原理" aria-label="Permalink to &quot;工作原理&quot;">​</a></h2><p>当请求携带 <code>model: &quot;auto&quot;</code> 时，WebRouter：</p><ol><li><strong>分析</strong> 请求——提示长度、复杂度指标、系统提示词</li><li><strong>评分</strong> 每个可用模型的能力与成本</li><li><strong>选择</strong> 最匹配的模型：简单请求走经济型，复杂推理走高端模型</li><li><strong>路由</strong> 请求到选中的 Provider</li></ol><h2 id="模型分级" tabindex="-1">模型分级 <a class="header-anchor" href="#模型分级" aria-label="Permalink to &quot;模型分级&quot;">​</a></h2><p>定义能力层级：</p><table tabindex="0"><thead><tr><th>等级</th><th>示例模型</th><th>适用场景</th></tr></thead><tbody><tr><td><code>premium</code></td><td>gpt-4o, claude-sonnet-4</td><td>复杂推理、代码生成</td></tr><tr><td><code>standard</code></td><td>gpt-4o-mini, deepseek-chat</td><td>通用场景</td></tr><tr><td><code>economy</code></td><td>qwen-turbo, claude-haiku</td><td>简单问答、分类</td></tr></tbody></table><h2 id="模型别名" tabindex="-1">模型别名 <a class="header-anchor" href="#模型别名" aria-label="Permalink to &quot;模型别名&quot;">​</a></h2><p>创建常用模型别名：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>gpt4 → gpt-4o</span></span>
<span class="line"><span>claude-sonnet → claude-sonnet-4</span></span>
<span class="line"><span>deepseek-v3 → deepseek-chat</span></span></code></pre></div><p>在应用中使用简短稳定的名称，WebRouter 自动映射到实际模型。</p><h2 id="降级与重试" tabindex="-1">降级与重试 <a class="header-anchor" href="#降级与重试" aria-label="Permalink to &quot;降级与重试&quot;">​</a></h2><p>Provider 失败时自动：</p><ol><li><strong>重试</strong> — 指数退避（最多 3 次）</li><li><strong>回退</strong> — 下一个可用 Provider</li><li><strong>智能降级</strong> — 自动切换到经济型模型完成请求</li></ol>`,16)])])}const g=e(d,[["render",n]]);export{u as __pageData,g as default};
